/**
 * Timing drift detection and correction mechanisms
 * Monitors timing precision and warns when accuracy degrades
 */

import { PrecisionClock, PrecisionTimestamp } from './PrecisionClock.js';

export interface DriftMeasurement {
  readonly timestamp: number;
  readonly audioPerformanceDelta: number;
  readonly rafPerformanceDelta: number;
  readonly jitter: number;
  readonly frequency: number;
}

export interface DriftStatus {
  readonly isAccurate: boolean;
  readonly maxObservedJitter: number;
  readonly averageJitter: number;
  readonly driftTrend: number;
  readonly warnings: string[];
  readonly recommendations: string[];
}

export class TimingDriftDetector {
  private measurements: DriftMeasurement[] = [];
  private warningThreshold: number = 2; // 2ms warning threshold
  private criticalThreshold: number = 5; // 5ms critical threshold
  private maxMeasurements: number = 1000;
  private measurementInterval: number = 100; // ms between measurements
  private intervalId: number | null = null;
  private clock: PrecisionClock;
  private lastMeasurement: number = 0;

  constructor(clock: PrecisionClock) {
    this.clock = clock;
  }

  /**
   * Start continuous drift monitoring
   */
  startMonitoring(): void {
    if (this.intervalId) {
      this.stopMonitoring();
    }

    this.intervalId = window.setInterval(() => {
      this.takeMeasurement();
    }, this.measurementInterval);
  }

  /**
   * Stop drift monitoring
   */
  stopMonitoring(): void {
    if (this.intervalId) {
      clearInterval(this.intervalId);
      this.intervalId = null;
    }
  }

  /**
   * Take a single drift measurement
   */
  takeMeasurement(): DriftMeasurement {
    const timestamp = this.clock.now();
    const measurement = this.calculateDriftMeasurement(timestamp);

    this.measurements.push(measurement);

    // Keep only recent measurements
    if (this.measurements.length > this.maxMeasurements) {
      this.measurements.shift();
    }

    return measurement;
  }

  /**
   * Get current drift status
   */
  getDriftStatus(): DriftStatus {
    if (this.measurements.length < 10) {
      return {
        isAccurate: true,
        maxObservedJitter: 0,
        averageJitter: 0,
        driftTrend: 0,
        warnings: ['Insufficient measurements for drift analysis'],
        recommendations: ['Continue monitoring to gather baseline data']
      };
    }

    const recentMeasurements = this.measurements.slice(-100);
    const jitters = recentMeasurements.map(m => m.jitter);
    const maxJitter = Math.max(...jitters);
    const averageJitter = jitters.reduce((a, b) => a + b, 0) / jitters.length;
    const driftTrend = this.calculateDriftTrend();

    const warnings: string[] = [];
    const recommendations: string[] = [];

    // Check for accuracy issues
    if (maxJitter > this.criticalThreshold) {
      warnings.push(`Critical timing jitter detected: ${maxJitter.toFixed(2)}ms`);
      recommendations.push('Consider reducing system load or switching to dedicated timing hardware');
    } else if (maxJitter > this.warningThreshold) {
      warnings.push(`High timing jitter detected: ${maxJitter.toFixed(2)}ms`);
      recommendations.push('Monitor system performance and close unnecessary applications');
    }

    // Check for drift trend
    if (Math.abs(driftTrend) > 0.1) {
      warnings.push(`Timing drift trend detected: ${driftTrend.toFixed(3)}ms/s`);
      recommendations.push('System clock may be unstable - consider calibration');
    }

    return {
      isAccurate: maxJitter <= this.warningThreshold,
      maxObservedJitter: maxJitter,
      averageJitter,
      driftTrend,
      warnings,
      recommendations
    };
  }

  /**
   * Get detailed measurement history
   */
  getMeasurementHistory(): DriftMeasurement[] {
    return [...this.measurements];
  }

  /**
   * Reset measurement history
   */
  reset(): void {
    this.measurements = [];
    this.lastMeasurement = 0;
  }

  /**
   * Set warning and critical thresholds in milliseconds
   */
  setThresholds(warningThreshold: number, criticalThreshold: number): void {
    this.warningThreshold = warningThreshold;
    this.criticalThreshold = criticalThreshold;
  }

  /**
   * Estimate timing precision based on measurements
   */
  estimatePrecision(): number {
    if (this.measurements.length < 10) {
      return 0;
    }

    const jitters = this.measurements.slice(-100).map(m => m.jitter);
    const sortedJitters = jitters.sort((a, b) => a - b);

    // Use 95th percentile as precision estimate
    const percentile95Index = Math.floor(sortedJitters.length * 0.95);
    return sortedJitters[percentile95Index] || 0;
  }

  /**
   * Check if timing meets specified precision requirements
   */
  meetsPrecisionRequirement(requiredPrecision: number): boolean {
    const estimatedPrecision = this.estimatePrecision();
    return estimatedPrecision <= requiredPrecision;
  }

  private calculateDriftMeasurement(timestamp: PrecisionTimestamp): DriftMeasurement {
    const now = Date.now();

    // Calculate deltas between different timing sources
    const audioPerformanceDelta = Math.abs(
      (timestamp.audioTime * 1000) - timestamp.performanceTime
    );

    const rafPerformanceDelta = Math.abs(
      timestamp.rafTime - timestamp.performanceTime
    );

    // Calculate jitter as deviation from expected timing
    const expectedInterval = this.measurementInterval;
    const actualInterval = this.lastMeasurement ? now - this.lastMeasurement : 0;
    const jitter = this.lastMeasurement ? Math.abs(actualInterval - expectedInterval) : 0;

    // Estimate frequency based on RAF timing
    const frequency = this.estimateDisplayFrequency(timestamp.rafTime);

    this.lastMeasurement = now;

    return {
      timestamp: now,
      audioPerformanceDelta,
      rafPerformanceDelta,
      jitter,
      frequency
    };
  }

  private calculateDriftTrend(): number {
    if (this.measurements.length < 20) {
      return 0;
    }

    const recentMeasurements = this.measurements.slice(-20);
    const xValues = recentMeasurements.map((_, i) => i);
    const yValues = recentMeasurements.map(m => m.audioPerformanceDelta);

    // Simple linear regression to detect trend
    const n = xValues.length;
    const sumX = xValues.reduce((a, b) => a + b, 0);
    const sumY = yValues.reduce((a, b) => a + b, 0);
    const sumXY = xValues.reduce((sum, x, i) => sum + (x * yValues[i]!), 0);
    const sumXX = xValues.reduce((sum, x) => sum + (x * x), 0);

    const slope = (n * sumXY - sumX * sumY) / (n * sumXX - sumX * sumX);

    // Convert slope to ms/s
    return slope * (1000 / this.measurementInterval);
  }

  private estimateDisplayFrequency(rafTime: number): number {
    // Simple frequency estimation based on RAF timing
    // This is a rough estimate and could be improved with more sophisticated analysis
    const recentRafTimes = this.measurements
      .slice(-10)
      .map(m => m.timestamp)
      .filter(t => t > 0);

    if (recentRafTimes.length < 2) {
      return 60; // Default assumption
    }

    const intervals = [];
    for (let i = 1; i < recentRafTimes.length; i++) {
      intervals.push(recentRafTimes[i]! - recentRafTimes[i - 1]!);
    }

    const averageInterval = intervals.reduce((a, b) => a + b, 0) / intervals.length;
    return averageInterval > 0 ? 1000 / averageInterval : 60;
  }
}

/**
 * Create a timing drift detector for the global precision clock
 */
export function createDriftDetector(clock: PrecisionClock): TimingDriftDetector {
  return new TimingDriftDetector(clock);
}

