/**
 * Tests for timing package exports and utilities
 */

import { describe, it, expect, vi } from 'vitest';
import { 
  isTimingSupported, 
  getTimingCapabilities,
  PrecisionClock,
  TimingDriftDetector
} from '../src/index.js';

// Mock global APIs
const mockGlobals = () => {
  global.AudioContext = vi.fn();
  global.performance = {
    now: vi.fn(() => 1000.123),
    timeOrigin: Date.now()
  } as any;
  global.requestAnimationFrame = vi.fn();
};

const clearGlobals = () => {
  delete (global as any).AudioContext;
  delete (global as any).performance;
  delete (global as any).requestAnimationFrame;
};

describe('Timing Package Exports', () => {
  describe('exports', () => {
    it('should export PrecisionClock class', () => {
      expect(PrecisionClock).toBeDefined();
      expect(typeof PrecisionClock).toBe('function');
    });

    it('should export TimingDriftDetector class', () => {
      expect(TimingDriftDetector).toBeDefined();
      expect(typeof TimingDriftDetector).toBe('function');
    });

    it('should export utility functions', () => {
      expect(typeof isTimingSupported).toBe('function');
      expect(typeof getTimingCapabilities).toBe('function');
    });
  });

  describe('isTimingSupported', () => {
    afterEach(clearGlobals);

    it('should return true when all APIs are available', () => {
      mockGlobals();

      const supported = isTimingSupported();

      expect(supported).toBe(true);
    });

    it('should return false when AudioContext is missing', () => {
      global.performance = { now: vi.fn() } as any;
      global.requestAnimationFrame = vi.fn();

      const supported = isTimingSupported();

      expect(supported).toBe(false);
    });

    it('should return false when performance is missing', () => {
      global.AudioContext = vi.fn();
      global.requestAnimationFrame = vi.fn();

      const supported = isTimingSupported();

      expect(supported).toBe(false);
    });

    it('should return false when performance.now is missing', () => {
      global.AudioContext = vi.fn();
      global.performance = {} as any;
      global.requestAnimationFrame = vi.fn();

      const supported = isTimingSupported();

      expect(supported).toBe(false);
    });

    it('should return false when requestAnimationFrame is missing', () => {
      global.AudioContext = vi.fn();
      global.performance = { now: vi.fn() } as any;

      const supported = isTimingSupported();

      expect(supported).toBe(false);
    });
  });

  describe('getTimingCapabilities', () => {
    afterEach(clearGlobals);

    it('should return full capabilities when all APIs available', async () => {
      mockGlobals();

      const capabilities = await getTimingCapabilities();

      expect(capabilities).toEqual({
        supported: true,
        audioContextSupported: true,
        performanceSupported: true,
        rafSupported: true,
        estimatedPrecision: expect.any(Number)
      });
    });

    it('should return partial capabilities when some APIs missing', async () => {
      global.performance = { now: vi.fn(() => 1000.123) } as any;
      global.requestAnimationFrame = vi.fn();
      // AudioContext missing

      const capabilities = await getTimingCapabilities();

      expect(capabilities).toEqual({
        supported: false,
        audioContextSupported: false,
        performanceSupported: true,
        rafSupported: true,
        estimatedPrecision: 0
      });
    });

    it('should estimate timing precision', async () => {
      mockGlobals();

      // Mock performance.now to return predictable values
      (global.performance.now as any)
        .mockReturnValueOnce(1000.0)
        .mockReturnValueOnce(1000.1)
        .mockReturnValueOnce(1000.2)
        .mockReturnValueOnce(1000.3);

      const capabilities = await getTimingCapabilities();

      expect(capabilities.estimatedPrecision).toBeGreaterThan(0);
      expect(capabilities.estimatedPrecision).toBe(100); // 0.1ms * 1000 = 100μs
    });

    it('should handle precision measurement with zero intervals', async () => {
      mockGlobals();

      // Mock performance.now to return same value (no precision)
      (global.performance.now as any).mockReturnValue(1000.0);

      const capabilities = await getTimingCapabilities();

      expect(capabilities.estimatedPrecision).toBe(0);
    });

    it('should return zero precision when timing not supported', async () => {
      // No global APIs

      const capabilities = await getTimingCapabilities();

      expect(capabilities).toEqual({
        supported: false,
        audioContextSupported: false,
        performanceSupported: false,
        rafSupported: false,
        estimatedPrecision: 0
      });
    });
  });

  describe('integration', () => {
    it('should allow creating and using timing components together', async () => {
      mockGlobals();

      const clock = new PrecisionClock();

      expect(() => {
        const detector = new TimingDriftDetector(clock);
        expect(detector).toBeInstanceOf(TimingDriftDetector);
      }).not.toThrow();
    });

    it('should provide consistent API surface', () => {
      // Verify all expected exports are available
      const exportedItems = [
        'PrecisionClock',
        'TimingDriftDetector', 
        'isTimingSupported',
        'getTimingCapabilities'
      ];

      exportedItems.forEach(item => {
        expect(eval(item)).toBeDefined();
      });
    });
  });

  describe('error handling', () => {
    it('should handle missing global APIs gracefully', () => {
      // Clear all globals
      clearGlobals();

      expect(() => isTimingSupported()).not.toThrow();
      expect(() => getTimingCapabilities()).not.toThrow();
    });

    it('should handle performance.now throwing error', async () => {
      global.AudioContext = vi.fn();
      global.performance = {
        now: vi.fn(() => {
          throw new Error('Performance API error');
        })
      } as any;
      global.requestAnimationFrame = vi.fn();

      const capabilities = await getTimingCapabilities();

      expect(capabilities.supported).toBe(false);
      expect(capabilities.estimatedPrecision).toBe(0);
    });
  });
});

