/**
 * Tests for PrecisionClock implementation
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { PrecisionClock } from '../src/PrecisionClock.js';

// Mock Web Audio API for testing
const mockAudioContext = {
  currentTime: 0,
  state: 'running',
  sampleRate: 44100,
  resume: vi.fn().mockResolvedValue(undefined),
  close: vi.fn().mockResolvedValue(undefined),
  createOscillator: vi.fn().mockReturnValue({
    connect: vi.fn(),
    start: vi.fn(),
    stop: vi.fn(),
    onended: null
  }),
  createGain: vi.fn().mockReturnValue({
    connect: vi.fn(),
    gain: { value: 0 }
  }),
  destination: {}
};

// Mock global APIs
global.AudioContext = vi.fn(() => mockAudioContext as any);
global.performance = {
  now: vi.fn(() => Date.now()),
  timeOrigin: Date.now()
} as any;
global.requestAnimationFrame = vi.fn((callback) => {
  setTimeout(() => callback(performance.now()), 16);
  return 1;
});
global.cancelAnimationFrame = vi.fn();

describe('PrecisionClock', () => {
  let clock: PrecisionClock;

  beforeEach(() => {
    clock = new PrecisionClock();
    vi.clearAllMocks();
  });

  afterEach(async () => {
    try {
      await clock.destroy();
    } catch {
      // Ignore cleanup errors in tests
    }
  });

  describe('initialization', () => {
    it('should initialize successfully', async () => {
      const context = await clock.initialize();

      expect(context).toHaveProperty('audioContext');
      expect(context).toHaveProperty('baseTime');
      expect(context).toHaveProperty('performanceOrigin');
      expect(AudioContext).toHaveBeenCalledOnce();
    });

    it('should throw error if already initialized', async () => {
      await clock.initialize();

      await expect(clock.initialize()).rejects.toThrow('PrecisionClock already initialized');
    });

    it('should resume suspended audio context', async () => {
      mockAudioContext.state = 'suspended';

      await clock.initialize();

      expect(mockAudioContext.resume).toHaveBeenCalledOnce();
    });
  });

  describe('timestamp generation', () => {
    beforeEach(async () => {
      await clock.initialize();
    });

    it('should generate valid timestamps', () => {
      mockAudioContext.currentTime = 1.234;
      (performance.now as any).mockReturnValue(5678.9);

      const timestamp = clock.now();

      expect(timestamp).toHaveProperty('audioTime', 1.234);
      expect(timestamp).toHaveProperty('performanceTime', 5678.9);
      expect(timestamp).toHaveProperty('rafTime');
      expect(timestamp).toHaveProperty('monotonic');
      expect(typeof timestamp.monotonic).toBe('number');
    });

    it('should throw error if not initialized', () => {
      const uninitializedClock = new PrecisionClock();

      expect(() => uninitializedClock.now()).toThrow('PrecisionClock not initialized');
    });

    it('should generate monotonic timestamps', () => {
      const timestamps = [];
      for (let i = 0; i < 10; i++) {
        mockAudioContext.currentTime += 0.001;
        timestamps.push(clock.now());
      }

      // Check that monotonic values are increasing
      for (let i = 1; i < timestamps.length; i++) {
        expect(timestamps[i]!.monotonic).toBeGreaterThanOrEqual(timestamps[i - 1]!.monotonic);
      }
    });
  });

  describe('callback scheduling', () => {
    beforeEach(async () => {
      await clock.initialize();
    });

    it('should schedule callbacks at specific times', () => {
      const callback = vi.fn();
      const targetTime = 2.0;

      clock.scheduleCallback(targetTime, callback);

      expect(mockAudioContext.createOscillator).toHaveBeenCalledOnce();
      expect(mockAudioContext.createGain).toHaveBeenCalledOnce();
    });

    it('should throw error if not initialized', () => {
      const uninitializedClock = new PrecisionClock();

      expect(() => {
        uninitializedClock.scheduleCallback(1.0, () => {});
      }).toThrow('PrecisionClock not initialized');
    });
  });

  describe('frame callbacks', () => {
    beforeEach(async () => {
      await clock.initialize();
    });

    it('should register and call frame callbacks', () => {
      const callback = vi.fn();

      const unsubscribe = clock.onFrame(callback);

      expect(typeof unsubscribe).toBe('function');
      expect(requestAnimationFrame).toHaveBeenCalled();
    });

    it('should unsubscribe frame callbacks', () => {
      const callback = vi.fn();

      const unsubscribe = clock.onFrame(callback);
      unsubscribe();

      // Should not call callback after unsubscribe
      // This is tested implicitly through RAF mock behavior
    });
  });

  describe('precision estimation', () => {
    beforeEach(async () => {
      await clock.initialize();
    });

    it('should estimate timing precision', () => {
      (performance.now as any)
        .mockReturnValueOnce(1000.0)
        .mockReturnValueOnce(1000.1)
        .mockReturnValueOnce(1000.2);

      const precision = clock.getPrecisionEstimate();

      expect(typeof precision).toBe('number');
      expect(precision).toBeGreaterThan(0);
    });

    it('should detect high-precision availability', () => {
      const available = clock.isHighPrecisionAvailable();

      expect(typeof available).toBe('boolean');
      expect(available).toBe(true);
    });
  });

  describe('cleanup', () => {
    it('should clean up resources on destroy', async () => {
      await clock.initialize();

      await clock.destroy();

      expect(mockAudioContext.close).toHaveBeenCalledOnce();
      expect(cancelAnimationFrame).toHaveBeenCalled();
    });

    it('should handle destroy without initialization', async () => {
      await expect(clock.destroy()).resolves.not.toThrow();
    });
  });

  describe('error handling', () => {
    it('should handle AudioContext creation failure', async () => {
      (global.AudioContext as any).mockImplementation(() => {
        throw new Error('AudioContext not supported');
      });

      await expect(clock.initialize()).rejects.toThrow('Failed to initialize PrecisionClock');
    });

    it('should handle frame callback errors gracefully', async () => {
      await clock.initialize();

      const errorCallback = vi.fn(() => {
        throw new Error('Callback error');
      });
      const goodCallback = vi.fn();

      clock.onFrame(errorCallback);
      clock.onFrame(goodCallback);

      // Should not throw despite error in callback
      expect(() => {
        // Simulate RAF callback execution
        const rafCallback = (requestAnimationFrame as any).mock.calls[0][0];
        rafCallback(performance.now());
      }).not.toThrow();
    });
  });
});

