/**
 * Tests for TimingDriftDetector implementation
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { PrecisionClock } from '../src/PrecisionClock.js';
import { TimingDriftDetector, createDriftDetector } from '../src/TimingDriftDetector.js';

// Mock the PrecisionClock
const mockClock = {
  now: vi.fn().mockReturnValue({
    audioTime: 1.234,
    performanceTime: 5678.9,
    rafTime: 5678.9,
    monotonic: 5678.9
  })
} as any;

// Mock global timers
global.setInterval = vi.fn((callback, interval) => {
  return 1 as any;
});
global.clearInterval = vi.fn();

describe('TimingDriftDetector', () => {
  let detector: TimingDriftDetector;

  beforeEach(() => {
    detector = new TimingDriftDetector(mockClock);
    vi.clearAllMocks();
  });

  afterEach(() => {
    detector.stopMonitoring();
  });

  describe('initialization', () => {
    it('should create detector with clock', () => {
      expect(detector).toBeInstanceOf(TimingDriftDetector);
    });

    it('should create detector using factory function', () => {
      const factoryDetector = createDriftDetector(mockClock);
      expect(factoryDetector).toBeInstanceOf(TimingDriftDetector);
    });
  });

  describe('monitoring', () => {
    it('should start monitoring', () => {
      detector.startMonitoring();

      expect(setInterval).toHaveBeenCalledWith(
        expect.any(Function),
        100 // Default interval
      );
    });

    it('should stop monitoring', () => {
      detector.startMonitoring();
      detector.stopMonitoring();

      expect(clearInterval).toHaveBeenCalledWith(1);
    });

    it('should restart monitoring if already running', () => {
      detector.startMonitoring();
      detector.startMonitoring();

      expect(clearInterval).toHaveBeenCalledWith(1);
      expect(setInterval).toHaveBeenCalledTimes(2);
    });
  });

  describe('measurements', () => {
    it('should take single measurement', () => {
      const measurement = detector.takeMeasurement();

      expect(measurement).toHaveProperty('timestamp');
      expect(measurement).toHaveProperty('audioPerformanceDelta');
      expect(measurement).toHaveProperty('rafPerformanceDelta');
      expect(measurement).toHaveProperty('jitter');
      expect(measurement).toHaveProperty('frequency');
      expect(mockClock.now).toHaveBeenCalledOnce();
    });

    it('should calculate audio-performance delta', () => {
      mockClock.now.mockReturnValue({
        audioTime: 1.000, // 1000ms
        performanceTime: 1005.0, // 5ms difference
        rafTime: 1005.0,
        monotonic: 1005.0
      });

      const measurement = detector.takeMeasurement();

      expect(measurement.audioPerformanceDelta).toBe(5.0);
    });

    it('should calculate RAF-performance delta', () => {
      mockClock.now.mockReturnValue({
        audioTime: 1.000,
        performanceTime: 1000.0,
        rafTime: 1003.0, // 3ms difference
        monotonic: 1000.0
      });

      const measurement = detector.takeMeasurement();

      expect(measurement.rafPerformanceDelta).toBe(3.0);
    });

    it('should track measurement history', () => {
      detector.takeMeasurement();
      detector.takeMeasurement();
      detector.takeMeasurement();

      const history = detector.getMeasurementHistory();
      expect(history).toHaveLength(3);
    });

    it('should limit measurement history', () => {
      // Take more measurements than the limit (1000)
      for (let i = 0; i < 1005; i++) {
        detector.takeMeasurement();
      }

      const history = detector.getMeasurementHistory();
      expect(history.length).toBeLessThanOrEqual(1000);
    });
  });

  describe('drift status', () => {
    it('should return insufficient data warning with few measurements', () => {
      const status = detector.getDriftStatus();

      expect(status.isAccurate).toBe(true);
      expect(status.warnings).toContain('Insufficient measurements for drift analysis');
    });

    it('should analyze drift with sufficient measurements', () => {
      // Add measurements with varying jitter
      for (let i = 0; i < 20; i++) {
        vi.spyOn(Date, 'now').mockReturnValue(i * 100);
        detector.takeMeasurement();
      }

      const status = detector.getDriftStatus();

      expect(status).toHaveProperty('isAccurate');
      expect(status).toHaveProperty('maxObservedJitter');
      expect(status).toHaveProperty('averageJitter');
      expect(status).toHaveProperty('driftTrend');
      expect(Array.isArray(status.warnings)).toBe(true);
      expect(Array.isArray(status.recommendations)).toBe(true);
    });

    it('should detect high jitter warnings', () => {
      // Mock high jitter scenario
      vi.spyOn(Date, 'now')
        .mockReturnValueOnce(0)
        .mockReturnValue(110); // 10ms jitter

      for (let i = 0; i < 20; i++) {
        detector.takeMeasurement();
      }

      const status = detector.getDriftStatus();

      expect(status.isAccurate).toBe(false);
      expect(status.warnings.some(w => w.includes('jitter'))).toBe(true);
    });
  });

  describe('precision estimation', () => {
    it('should estimate precision from measurements', () => {
      // Add measurements with known jitter patterns
      for (let i = 0; i < 20; i++) {
        vi.spyOn(Date, 'now').mockReturnValue(i * 100 + (i % 2)); // 1ms jitter pattern
        detector.takeMeasurement();
      }

      const precision = detector.estimatePrecision();

      expect(typeof precision).toBe('number');
      expect(precision).toBeGreaterThanOrEqual(0);
    });

    it('should return 0 precision with insufficient data', () => {
      const precision = detector.estimatePrecision();
      expect(precision).toBe(0);
    });

    it('should check precision requirements', () => {
      // Add measurements with 1ms precision - reset the measurements first
      detector.reset();

      for (let i = 0; i < 20; i++) {
        vi.spyOn(Date, 'now').mockReturnValue(i * 100 + 1);
        detector.takeMeasurement();
      }

      const precision = detector.estimatePrecision();
      expect(detector.meetsPrecisionRequirement(2.0)).toBe(true);
      expect(detector.meetsPrecisionRequirement(0.1)).toBe(false);
    });
  });

  describe('configuration', () => {
    it('should set custom thresholds', () => {
      detector.setThresholds(1.0, 3.0);

      // Add measurements with 2ms jitter
      for (let i = 0; i < 20; i++) {
        vi.spyOn(Date, 'now').mockReturnValue(i * 100 + 2);
        detector.takeMeasurement();
      }

      const status = detector.getDriftStatus();
      expect(status.isAccurate).toBe(false); // Should exceed 1ms threshold
    });

    it('should reset measurements', () => {
      detector.takeMeasurement();
      detector.takeMeasurement();

      detector.reset();

      const history = detector.getMeasurementHistory();
      expect(history).toHaveLength(0);
    });
  });

  describe('frequency estimation', () => {
    it('should estimate display frequency', () => {
      // Mock regular 60Hz intervals
      for (let i = 0; i < 10; i++) {
        vi.spyOn(Date, 'now').mockReturnValue(i * 16.67); // 60Hz = ~16.67ms intervals
        detector.takeMeasurement();
      }

      const measurement = detector.takeMeasurement();

      // Should estimate around 60Hz
      expect(measurement.frequency).toBeGreaterThan(50);
      expect(measurement.frequency).toBeLessThan(70);
    });
  });

  describe('drift trend analysis', () => {
    it('should detect positive drift trend', () => {
      // Mock increasing audio-performance delta over time
      for (let i = 0; i < 25; i++) {
        mockClock.now.mockReturnValue({
          audioTime: 1.000,
          performanceTime: 1000.0 + (i * 0.1), // Increasing delta
          rafTime: 1000.0,
          monotonic: 1000.0
        });
        detector.takeMeasurement();
      }

      const status = detector.getDriftStatus();

      expect(status.driftTrend).toBeGreaterThan(0);
      expect(status.warnings.some(w => w.includes('drift trend'))).toBe(true);
    });

    it('should detect negative drift trend', () => {
      // Mock decreasing audio-performance delta over time
      for (let i = 0; i < 25; i++) {
        mockClock.now.mockReturnValue({
          audioTime: 1.000,
          performanceTime: 1000.0 - (i * 0.1), // Decreasing delta
          rafTime: 1000.0,
          monotonic: 1000.0
        });
        detector.takeMeasurement();
      }

      const status = detector.getDriftStatus();

      expect(status.driftTrend).toBeLessThan(0);
    });
  });
});

